<?php
namespace App\Http\Controllers\Api;
use App\Http\Controllers\Controller;use Illuminate\Http\Request;use App\Services\{AuthService,UserService,CategoryService,CulinaryPlaceService,ReviewService,ReservationService,NotificationService};
class AuthController extends Controller{public function register(Request $r,AuthService $s){$data=$r->validate(['name'=>'required','email'=>'required|email|unique:users','password'=>'required|min:8','phone'=>'nullable']);return response()->json($s->register($data),201);} public function login(Request $r,AuthService $s){return response()->json($s->login($r->validate(['email'=>'required|email','password'=>'required'])));} public function logout(Request $r){$r->user()->currentAccessToken()?->delete();return response()->json(['message'=>'logged out']);} public function profile(Request $r){return $r->user();} public function updateProfile(Request $r,UserService $s){return $s->updateProfile($r->user(),$r->validate(['name'=>'sometimes','phone'=>'nullable','avatar'=>'nullable']));} public function forgotPassword(Request $r){return response()->json(['message'=>'Reset link diproses']);} public function resetPassword(Request $r){return response()->json(['message'=>'Password diperbarui']);}}
